-- ? ACERCANDONOS

-- * 6. `SSI_TALLERES`




SELECT 
   t.* 
FROM SSI_OBJETIVOS_ESPECIFICOS o
JOIN SSI_MODULOS m ON o.OE_ID_OBJETIVO = m.OE_ID_OBJETIVO
JOIN SSI_UNIDADES u ON m.MO_ID_MODULO = u.MO_ID_MODULO
JOIN SSI_UNIDAD_SESIONES s ON u.UN_ID_UNIDAD = s.UN_ID_UNIDAD
JOIN SSI_TALLERES t ON s.SE_ID_SESION = t.SE_ID_SESION
WHERE
   o.OE_ID_OBJETIVO IN (1, 2)
   AND t.TA_DESCRIPCION IS NOT NULL
/




-- ! COMMIT;

SELECT * FROM SSI_TALLERES t
ORDER BY t.TA_ID_TALLER DESC;

